        return false
        #else
        let bundlePath = Bundle.main.bundlePath
        let bundleURL = URL(fileURLWithPath: bundlePath)
        
        guard let attributes = try? FileManager.default.attributesOfItem(atPath: bundlePath) else {
            return true
        }
        
        let modificationDate = attributes[.modificationDate] as? Date ?? Date()
        let now = Date()
        
        if now.timeIntervalSince(modificationDate) > 300 {
            return true
        }
        
        return false
        #endif
    }
    
    func performSecurityChecks() -> Bool {
        return !isJailbroken() && !isDebugged() && !checkTampering()
