// MARK: - Transaction Signing
class TransactionSigner {
    static let shared = TransactionSigner()
    
    private init() {}
    
    func signTransaction(transaction: Data, with privateKey: Data) -> Data? {
        guard let signingKey = P256.Signing.PrivateKey(rawRepresentation: privateKey) else {
            return nil
        }
        
        do {
            let signature = try signingKey.sign(message: transaction)
            return signature.rawRepresentation
        } catch {
            return nil
        }
    }
    
    func verifySignature(transaction: Data, signature: Data, publicKey: Data) -> Bool {
        guard let verificationKey = P256.Signing.PublicKey(rawRepresentation: publicKey) else {
            return false
        }
        
        do {
            return try verificationKey.verify(signature: signature, for: transaction)
        } catch {
            return false
        }
    }
}

// MARK: - Blockchain Communication
class BlockchainClient {
    static let shared = BlockchainClient()
    private let baseURL = "https://api.blockchain.info"
    
    private init() {}
    
    func getBalance(address: String) async -> Result<Double, Error> {
        guard let url = URL(string: "\(baseURL)/balance?active=\(address)") else {
            return .failure(NetworkError.invalidURL)
        }
        
        do {
            let (data, response) = try await URLSession.shared.data(from: url)
            
            guard let httpResponse = response as? HTTPURLResponse else {
                return .failure(NetworkError.invalidResponse)
            }
            
            guard httpResponse.statusCode == 200 else {
                return .failure(NetworkError.httpError(httpResponse.statusCode))
            }
            
            let json = try JSONSerialization.jsonObject(with: data) as? [String: Any]
            let balance = json?[address] as? Double ?? 0.0
            
            return .success(balance)
        } catch {
            return .failure(error)
        }
    }
    
    func sendTransaction(transaction: Data, signature: Data) async -> Result<String, Error> {
        guard let url = URL(string: "\(baseURL)/send") else {
            return .failure(NetworkError.invalidURL)
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.httpBody = transaction
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        do {
            let (data, response) = try await URLSession.shared.data(for: request)
            
            guard let httpResponse = response as? HTTPURLResponse else {
                return .failure(NetworkError.invalidResponse)
            }
            
            guard httpResponse.statusCode == 200 else {
                return .failure(NetworkError.httpError(httpResponse.statusCode))
            }
            
            if let responseString = String(data: data, encoding: .utf8) {
                return .success(responseString)
            }
            
            return .failure(NetworkError.invalidResponse)
        } catch {
            return .failure(error)
        }
    }
}

