// MARK: - Wallet Manager
class WalletManager {
    static let shared = WalletManager()
    private let keyManager = KeyManager.shared
    private let integrityChecker = IntegrityChecker.shared
    private let transactionSigner = TransactionSigner.shared
    private let blockchainClient = BlockchainClient.shared
    
    private init() {}
    
    func createWallet() -> String? {
        guard integrityChecker.performSecurityChecks() else {
            return nil
        }
        
        let (privateKey, publicKey) = keyManager.generateKeyPair()
        let address = generateAddress(from: publicKey)
        
        guard keyManager.storePrivateKey(privateKey, for: address) else {
            return nil
        }
        
        return address
    }
    
    func signTransaction(transaction: Data, for address: String) -> Data? {
        guard integrityChecker.performSecurityChecks() else {
            return nil
        }
        
        guard let privateKey = keyManager.retrievePrivateKey(for: address) else {
            return nil
        }
        
        return transactionSigner.signTransaction(transaction: transaction, with: privateKey)
    }
    
    func sendTransaction(transaction: Data, signature: Data, to address: String) async -> Result<String, Error> {
        guard integrityChecker.performSecurityChecks() else {
            return .failure(NetworkError.invalidResponse)
        }
        
        return await blockchainClient.sendTransaction(transaction: transaction, signature: signature)
    }
    
    func getBalance(for address: String) async -> Result<Double, Error> {
        guard integrityChecker.performSecurityChecks() else {
            return .failure(NetworkError.invalidResponse)
        }
        
        return await blockchainClient.getBalance(address: address)
    }
    
    private func generateAddress(from publicKey: Data) -> String {
        let hash = SHA256.hash(data: publicKey)
        return hash.compactMap { String(format: "%02x", $0) }.joined()
    }
}

